#!/usr/bin/env node
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';
import { spawnSync } from 'node:child_process';

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(here, '../../../..');

function argValue(name) {
  const index = process.argv.indexOf(name);
  if (index < 0 || index + 1 >= process.argv.length) return null;
  return process.argv[index + 1];
}

const expected = Number(argValue('--expected'));
if (expected !== 1) {
  console.error(`[openai-gateway-qspec] reject expected=${expected}; only expected=1 admits`);
  process.exit(2);
}

const result = spawnSync(
  'bun',
  [
    'test',
    'apps/edge-workers/src/__tests__/durables/mesh-fat-client-do.test.ts',
    '--preload',
    './bun.preload.ts',
  ],
  {
    cwd: repoRoot,
    env: process.env,
    stdio: 'inherit',
  },
);

if (result.error) {
  console.error(`[openai-gateway-qspec] failed to run gateway quality gate: ${result.error.message}`);
  process.exit(1);
}

process.exit(result.status ?? 1);
